import sys
import requests

def debug_api(url: str) -> None:
    try:
        r = requests.get(url, timeout=10)
    except requests.exceptions.RequestException as e:
        print(f'Connection error: {e}')
        return

    print(f'Status: {r.status_code} {r.reason}')

    # Rate/limit related headers
    keywords = ('rate', 'limit', 'retry', 'request-id')
    notable = {k: v for k, v in r.headers.items()
               if any(kw in k.lower() for kw in keywords)}
    if notable:
        print('Notable headers:')
        for k, v in notable.items():
            print(f'  {k}: {v}')

    # Diagnosis
    code = r.status_code
    if code == 200:
        print('✅ Success')
    elif code == 401:
        print('❌ Check your API key')
    elif code == 429:
        wait = r.headers.get('Retry-After', 'unknown')
        print(f'⏳ Rate limited — wait {wait} seconds')
    elif code >= 500:
        print('🔥 Server error — retry with backoff')
    else:
        print('❓ Unknown — check docs')

if __name__ == '__main__':
    url = sys.argv[1] if len(sys.argv) > 1 else 'https://httpbin.org/get'
    debug_api(url)

