import time, random

def get_retry_wait(response, attempt: int, base_delay: float = 1.0) -> float:
    if response.status_code == 429:
        retry_after = response.headers.get('Retry-After')
        if retry_after:
            return float(retry_after)
    # Exponential backoff + jitter for all retryable errors
    return base_delay * (2 ** attempt) + random.uniform(0, 1)
